import path from "node:path";

import { logEvent } from "../logger.js";
import { TerminalSessionRunner } from "./runners/terminal-session-runner.js";

const SESSION_CWD_QUERY_TIMEOUT_MS = 4000;

export class PtySessionManager {
  constructor(config, loggers, profileRegistry, sessionStore) {
    this.config = config;
    this.commandLogger = loggers.commandLogger;
    this.profileRegistry = profileRegistry;
    this.sessionStore = sessionStore;
    this.runner = new TerminalSessionRunner(config);
    this.handles = new Map();
    this.pendingCwdQueries = new Map();
  }

  createSession({
    sessionId,
    agentId,
    requestId,
    source,
    profileName,
    cwd,
    env = {},
    cols,
    rows,
    eventSink = null
  }) {
    if (this.handles.size >= this.config.maxTerminalSessions) {
      throw new Error(`已达到最大终端会话数: ${this.config.maxTerminalSessions}`);
    }

    const launch = this.profileRegistry.resolveSessionLaunch({
      profileName,
      cwd,
      env
    });

    this.sessionStore.create({
      sessionId,
      agentId,
      requestId,
      source,
      profile: profileName,
      sessionType: "pty",
      cwd: launch.cwd,
      envKeys: Object.keys(env || {}),
      cols,
      rows,
      metadata: {
        profileLabel: String(launch.profile?.label || profileName),
        profileSource: String(launch.profile?.source || ""),
        profileKind: String(launch.profile?.kind || "")
      }
    });

    let ptyProcess;
    try {
      ptyProcess = this.runner.spawnSession({
        command: launch.command,
        args: launch.args,
        cwd: launch.cwd,
        env: launch.env,
        cols,
        rows
      });
    } catch (error) {
      this.sessionStore.update(sessionId, {
        status: "failed",
        error: error.message,
        closedAt: new Date().toISOString()
      });
      throw error;
    }

    const handle = {
      sessionId,
      agentId,
      source,
      profileName,
      profileLabel: String(launch.profile?.label || profileName),
      profileSource: String(launch.profile?.source || ""),
      profileKind: String(launch.profile?.kind || ""),
      ptyProcess,
      eventSink,
      idleTimer: null,
      terminatingReason: ""
    };

    this.handles.set(sessionId, handle);
    this.armIdleTimer(handle);

    const startedAt = new Date().toISOString();
    this.sessionStore.update(sessionId, {
      status: "running",
      pid: ptyProcess.pid,
      startedAt
    });

    logEvent(this.commandLogger, "info", "terminal.session.created", {
      sessionId,
      requestId,
      agentId,
      profile: profileName,
      profileLabel: handle.profileLabel,
      profileSource: handle.profileSource,
      profileKind: handle.profileKind,
      source,
      pid: ptyProcess.pid
    });

    this.emit(handle, "terminal.session.created", {
      sessionId,
      requestId,
      agentId,
      profile: profileName,
      profileLabel: handle.profileLabel,
      profileSource: handle.profileSource,
      profileKind: handle.profileKind,
      status: "running",
      pid: ptyProcess.pid,
      startedAt
    }, true);

    ptyProcess.onData((chunk) => {
      this.touchSession(handle);
      const appended = this.sessionStore.appendOutput(sessionId, {
        stream: "stdout",
        chunk,
        sentAt: new Date().toISOString()
      });

      if (!appended) {
        return;
      }

      logEvent(this.commandLogger, "info", "terminal.session.output", {
        sessionId,
        agentId,
        profile: profileName,
        profileLabel: handle.profileLabel,
        chunkLength: chunk.length
      });

      this.emit(handle, "terminal.session.output", {
        agentId,
        profile: profileName,
        profileLabel: handle.profileLabel,
        ...appended.output
      });
    });

    ptyProcess.onExit(({ exitCode, signal }) => {
      this.handleExit(handle, exitCode, signal);
    });

    return this.sessionStore.get(sessionId);
  }

  writeInput(sessionId, input) {
    const handle = this.getRequiredHandle(sessionId);
    handle.ptyProcess.write(input);
    this.touchSession(handle);
    this.sessionStore.update(sessionId, {
      lastInputAt: new Date().toISOString()
    });

    logEvent(this.commandLogger, "info", "terminal.session.input", {
      sessionId,
      agentId: handle.agentId,
      inputLength: input.length
    });

    return this.sessionStore.get(sessionId);
  }

  resizeSession(sessionId, cols, rows) {
    const handle = this.getRequiredHandle(sessionId);
    const normalizedCols = normalizeTerminalDimension(cols);
    const normalizedRows = normalizeTerminalDimension(rows);

    if (!normalizedCols || !normalizedRows) {
      throw new Error("终端尺寸无效");
    }

    handle.ptyProcess.resize(normalizedCols, normalizedRows);
    this.touchSession(handle);
    const session = this.sessionStore.update(sessionId, {
      cols: normalizedCols,
      rows: normalizedRows
    });

    logEvent(this.commandLogger, "info", "terminal.session.resized", {
      sessionId,
      agentId: handle.agentId,
      cols: normalizedCols,
      rows: normalizedRows
    });

    this.emit(handle, "terminal.session.resized", {
      sessionId,
      agentId: handle.agentId,
      profile: handle.profileName,
      profileLabel: handle.profileLabel,
      cols: normalizedCols,
      rows: normalizedRows,
      resizedAt: session?.updatedAt || new Date().toISOString()
    }, true);

    return session;
  }

  terminateSession(sessionId, reason = "terminated") {
    const handle = this.getRequiredHandle(sessionId);
    handle.terminatingReason = reason;
    this.sessionStore.update(sessionId, {
      status: "terminating"
    });
    handle.ptyProcess.kill();
    return this.sessionStore.get(sessionId);
  }

  terminateBySource(source, reason) {
    for (const handle of this.handles.values()) {
      if (handle.source === source) {
        handle.terminatingReason = reason;
        handle.ptyProcess.kill();
      }
    }
  }

  getSession(sessionId) {
    return this.sessionStore.get(sessionId);
  }

  listSessions() {
    return this.sessionStore.list();
  }

  listRemoteSessions(options = {}) {
    const activeOnly = options.activeOnly === true;

    return this.sessionStore
      .list()
      .filter((session) => session?.source === "remote")
      .filter((session) => !activeOnly || !isClosedSessionStatus(session.status));
  }

  querySessionCwd(sessionId, filePath = "") {
    const normalizedSessionId = String(sessionId || "").trim();
    const normalizedFilePath = String(filePath || "").trim();

    if (!normalizedSessionId || !normalizedFilePath || path.isAbsolute(normalizedFilePath)) {
      return Promise.resolve("");
    }

    const pending = this.pendingCwdQueries.get(normalizedSessionId);

    if (pending) {
      return pending;
    }

    const promise = this.querySessionCwdInternal(normalizedSessionId).finally(() => {
      this.pendingCwdQueries.delete(normalizedSessionId);
    });

    this.pendingCwdQueries.set(normalizedSessionId, promise);
    return promise;
  }

  getRequiredHandle(sessionId) {
    const handle = this.handles.get(sessionId);

    if (!handle) {
      throw new Error(`终端会话不存在: ${sessionId}`);
    }

    return handle;
  }

  armIdleTimer(handle) {
    this.clearIdleTimer(handle);

    handle.idleTimer = setTimeout(() => {
      handle.terminatingReason = "idle_timeout";
      handle.ptyProcess.kill();
    }, this.config.sessionIdleTimeoutMs);
  }

  clearIdleTimer(handle) {
    if (handle.idleTimer) {
      clearTimeout(handle.idleTimer);
      handle.idleTimer = null;
    }
  }

  touchSession(handle) {
    this.armIdleTimer(handle);
  }

  async querySessionCwdInternal(sessionId) {
    const handle = this.getRequiredHandle(sessionId);
    const profile = this.profileRegistry.getProfile(handle.profileName);
    const probe = createSessionCwdProbe(profile.command);

    if (!probe) {
      throw new Error("当前终端类型暂不支持自动获取实时目录，请直接输入绝对路径");
    }

    this.touchSession(handle);
    const cwd = await readSessionCwdFromPty(handle.ptyProcess, probe);

    if (!cwd) {
      throw new Error("当前终端目录为空，无法解析相对路径");
    }

    return cwd;
  }

  handleExit(handle, exitCode, signal) {
    this.clearIdleTimer(handle);
    this.handles.delete(handle.sessionId);

    const closedAt = new Date().toISOString();
    const status = handle.terminatingReason
      ? "terminated"
      : exitCode === 0
        ? "completed"
        : "failed";
    const error =
      status === "failed" ? `Terminal session exited with code ${exitCode ?? "unknown"}.` : "";

    this.sessionStore.update(handle.sessionId, {
      status,
      exitCode: typeof exitCode === "number" ? exitCode : null,
      error,
      closedAt
    });

    logEvent(this.commandLogger, status === "completed" ? "info" : "warn", "terminal.session.closed", {
      sessionId: handle.sessionId,
      agentId: handle.agentId,
      profile: handle.profileName,
      profileLabel: handle.profileLabel,
      status,
      exitCode: typeof exitCode === "number" ? exitCode : null,
      signal: signal || "",
      reason: handle.terminatingReason || ""
    });

    this.emit(handle, "terminal.session.closed", {
      sessionId: handle.sessionId,
      agentId: handle.agentId,
      profile: handle.profileName,
      profileLabel: handle.profileLabel,
      profileSource: handle.profileSource,
      profileKind: handle.profileKind,
      status,
      exitCode: typeof exitCode === "number" ? exitCode : null,
      signal: signal || "",
      reason: handle.terminatingReason || "",
      error,
      closedAt
    }, true);
  }

  emit(handle, type, payload, persistIfOffline = false) {
    if (typeof handle.eventSink !== "function") {
      return;
    }

    try {
      handle.eventSink({
        type,
        payload,
        persistIfOffline
      });
    } catch (error) {
      logEvent(this.commandLogger, "error", "terminal.session.emit_failed", {
        sessionId: handle.sessionId,
        type,
        error: error.message
      });
    }
  }
}

function isClosedSessionStatus(status) {
  return ["completed", "failed", "terminated"].includes(String(status || ""));
}

function normalizeTerminalDimension(value) {
  const parsed = Math.floor(Number(value));
  return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
}

function createSessionCwdProbe(command) {
  const startMarker = String.fromCharCode(30);
  const endMarker = String.fromCharCode(31);
  const executableName = path.basename(String(command || "").trim()).toLowerCase();

  if (["powershell", "powershell.exe", "pwsh", "pwsh.exe"].includes(executableName)) {
    return {
      startMarker,
      endMarker,
      input: `Write-Output ([char]30 + (pwd | Select-Object -ExpandProperty Path) + [char]31)\r`
    };
  }

  if (executableName === "cmd" || executableName === "cmd.exe") {
    return {
      startMarker,
      endMarker,
      input: `for /f "delims=" %i in ('cd') do <nul set /p=${startMarker}%i${endMarker} & echo.\r`
    };
  }

  if (["bash", "sh", "zsh", "fish"].includes(executableName)) {
    return {
      startMarker,
      endMarker,
      input: `printf '\\036'; pwd | tr -d '\\r\\n'; printf '\\037\\n'\r`
    };
  }

  return null;
}

function readSessionCwdFromPty(ptyProcess, probe) {
  return new Promise((resolve, reject) => {
    let settled = false;
    let output = "";
    let timeout = null;
    let subscription = null;

    const cleanup = () => {
      if (timeout) {
        clearTimeout(timeout);
        timeout = null;
      }

      if (subscription?.dispose) {
        subscription.dispose();
      }
    };

    const finish = (callback) => {
      if (settled) {
        return;
      }

      settled = true;
      cleanup();
      callback();
    };

    subscription = ptyProcess.onData((chunk) => {
      output += String(chunk || "");
      const cwd = extractSessionCwdFromOutput(output, probe.startMarker, probe.endMarker);

      if (!cwd) {
        return;
      }

      finish(() => resolve(cwd));
    });

    timeout = setTimeout(() => {
      finish(() =>
        reject(new Error("获取当前终端目录超时，请确认当前会话仍可交互"))
      );
    }, SESSION_CWD_QUERY_TIMEOUT_MS);

    try {
      ptyProcess.write(probe.input);
    } catch (error) {
      finish(() => reject(error));
    }
  });
}

function extractSessionCwdFromOutput(output, startMarker, endMarker) {
  const text = stripAnsiSequences(String(output || ""));
  const startIndex = text.lastIndexOf(startMarker);

  if (startIndex < 0) {
    return "";
  }

  const endIndex = text.indexOf(endMarker, startIndex + startMarker.length);

  if (endIndex < 0) {
    return "";
  }

  const rawValue = text.slice(startIndex + startMarker.length, endIndex);
  return rawValue.replace(/[\r\n]+/g, "").trim();
}

function stripAnsiSequences(text) {
  return String(text || "")
    .replace(/\u001b\][^\u0007]*(?:\u0007|\u001b\\)/g, "")
    .replace(/\u001bP[\s\S]*?(?:\u0007|\u001b\\)/g, "")
    .replace(/\u001b\[[0-?]*[ -/]*[@-~]/g, "")
    .replace(/\u001b[@-_]/g, "");
}
